import React, { useEffect, useRef, useState, useCallback } from 'react';
import { createRoot } from 'react-dom/client';

// --- 类型定义 ---
interface Point {
  x: number;
  y: number;
}

interface Particle {
  x: number;
  y: number;
  vx: number;
  vy: number;
  life: number;
  maxLife: number;
  color: string;
  size: number;
  friction: number;
  gravity: number;
  trail: Point[];
  behavior?: 'normal' | 'spark' | 'flash';
  wobbleSpeed?: number;
  wobbleTheta?: number;
}

interface FireworkProjectile {
  x: number;
  y: number;
  targetY: number;
  vx: number;
  vy: number;
  color: string;
  power: number;
  trail: Point[];
  active: boolean;
}

interface Blessing {
  text: string;
  opacity: number;
  y: number;
  id: number;
}

// --- 常量配置 ---
const QUOTES = [
  "醉后不知天在水，满船清梦压星河",
  "星河滚烫，你是人间理想",
  "愿你遍历山河，觉得人间值得",
  "今夜星轨，为你绕行三圈",
  "风起时，好运正穿过山海奔向你",
  "且听风吟，静待花开",
  "以渺小启程，以伟大结束",
  "万事胜意，喜乐长安",
  "保持热爱，奔赴山海",
  "满眼星辰，尽是未来",
  "在这孤独的宇宙里，总有人为你亮灯",
  "愿所有美好，都不期而遇",
  "心之所向，便是光亮",
  "温柔半两，从容一生",
  "知足且上进，温柔而坚定"
];

const COLORS = [
  '#E0C097', '#D4AF37', '#A3B18A', '#A8D8EA', '#AA96DA', 
  '#E6BEBB', '#95A5A6', '#F4EAD5', '#B85C38', '#E0F0FF',
];

const SUMI_COLORS = [
  '#1a1a1a', '#4a4a4a', '#8a8a8a', '#d4af37',
];

// --- 音效服务 ---
class AudioService {
  private ctx: AudioContext | null = null;
  private masterGain: GainNode | null = null;
  private volume: number = 0.5;

  private init() {
    if (!this.ctx) {
      const AudioCtx = (window as any).AudioContext || (window as any).webkitAudioContext;
      if (!AudioCtx) return;
      this.ctx = new AudioCtx();
      this.masterGain = this.ctx.createGain();
      this.masterGain.gain.setValueAtTime(this.volume, this.ctx.currentTime);
      this.masterGain.connect(this.ctx.destination);
    }
    if (this.ctx.state === 'suspended') {
      this.ctx.resume().catch(() => {});
    }
  }

  setVolume(value: number) {
    this.volume = value;
    if (this.masterGain && this.ctx) {
      try {
        this.masterGain.gain.setTargetAtTime(value, this.ctx.currentTime, 0.05);
      } catch (e) {
        // Ignore potential timing errors
      }
    }
  }

  getVolume() {
    return this.volume;
  }

  playLaunch() {
    this.init();
    if (!this.ctx || !this.masterGain) return;
    try {
      const osc = this.ctx.createOscillator();
      const g = this.ctx.createGain();
      osc.type = 'sine';
      osc.frequency.setValueAtTime(400, this.ctx.currentTime);
      osc.frequency.exponentialRampToValueAtTime(1200, this.ctx.currentTime + 0.3);
      g.gain.setValueAtTime(0.05 * this.volume, this.ctx.currentTime);
      g.gain.exponentialRampToValueAtTime(0.001, this.ctx.currentTime + 0.3);
      osc.connect(g);
      g.connect(this.masterGain);
      osc.start();
      osc.stop(this.ctx.currentTime + 0.3);
    } catch (e) { console.error(e); }
  }

  playPop(power: number) {
    this.init();
    if (!this.ctx || !this.masterGain) return;
    try {
      const g = this.ctx.createGain();
      const osc = this.ctx.createOscillator();
      osc.type = 'triangle';
      osc.frequency.setValueAtTime(100 + Math.random() * 50, this.ctx.currentTime);
      g.gain.setValueAtTime(0.1 * power * this.volume, this.ctx.currentTime);
      g.gain.exponentialRampToValueAtTime(0.001, this.ctx.currentTime + 0.5);
      osc.connect(g);
      g.connect(this.masterGain);
      osc.start();
      osc.stop(this.ctx.currentTime + 0.5);

      if (Math.random() > 0.5) {
        const chime = this.ctx.createOscillator();
        const cg = this.ctx.createGain();
        chime.type = 'sine';
        chime.frequency.setValueAtTime(800 + Math.random() * 1000, this.ctx.currentTime);
        cg.gain.setValueAtTime(0.02 * this.volume, this.ctx.currentTime);
        cg.gain.exponentialRampToValueAtTime(0.001, this.ctx.currentTime + 1);
        chime.connect(cg);
        cg.connect(this.masterGain);
        chime.start();
        chime.stop(this.ctx.currentTime + 1);
      }
    } catch (e) { console.error(e); }
  }
}

const audioService = new AudioService();

// --- 主程序组件 ---
const App: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [charging, setCharging] = useState(false);
  const [chargeLevel, setChargeLevel] = useState(0);
